(function(){
  const wrap=document.getElementById('telwrap'),btn=document.getElementById('telbtn'),drop=document.getElementById('teldrop'),
        list=document.getElementById('tellist'),search=document.getElementById('telsearch'),
        flagEl=document.getElementById('telflag'),codeEl=document.getElementById('telcode'),phone=document.getElementById('phone');
  if(!wrap)return;
  let cur=DIAL[0];
  const fsvg=(c,w)=>`<svg viewBox="0 0 30 20" width="${w||22}" xmlns="http://www.w3.org/2000/svg">${FLAGS[c]||''}</svg>`;
  function setCur(d){cur=d;flagEl.innerHTML=fsvg(d[1],22);codeEl.textContent=d[2];}
  setCur(cur);
  function renderList(q=""){
    q=q.trim().toLowerCase();
    const items=DIAL.filter(d=>!q||d[0].toLowerCase().includes(q)||d[2].includes(q)||d[1].includes(q));
    if(!items.length){list.innerHTML='<div class="telempty">No match found</div>';return;}
    list.innerHTML=items.map(d=>`<button type="button" class="telrow${d===cur?' active':''}" data-iso="${d[1]}" data-dial="${d[2]}" data-name="${d[0]}"><span class="rf">${fsvg(d[1],24)}</span><span class="rn">${d[0]}</span><span class="rc">${d[2]}</span></button>`).join('');
  }
  renderList();
  function open(){wrap.classList.add('open');btn.setAttribute('aria-expanded','true');search.value='';renderList();setTimeout(()=>search.focus(),50);}
  function close(){wrap.classList.remove('open');btn.setAttribute('aria-expanded','false');}
  btn.addEventListener('click',e=>{e.stopPropagation();wrap.classList.contains('open')?close():open();});
  search.addEventListener('input',()=>renderList(search.value));
  list.addEventListener('click',e=>{const r=e.target.closest('.telrow');if(!r)return;
    setCur([r.dataset.name,r.dataset.iso,r.dataset.dial]);close();phone.focus();});
  document.addEventListener('click',e=>{if(!wrap.contains(e.target))close();});
  phone.addEventListener('focus',()=>wrap.classList.add('focus'));
  phone.addEventListener('blur',()=>wrap.classList.remove('focus'));
  // keyboard: Esc closes
  wrap.addEventListener('keydown',e=>{if(e.key==='Escape')close();});
})();

document.getElementById('freset').onclick=()=>{ef.reset();ef.style.display='grid';fs.style.display='none';eb.disabled=false;eb.textContent='Get My Free Medical Opinion';eb.style.opacity='1'};


/* hide floating CTA + FABs when footer is visible (prevents covering policy links) */
const fcta=document.querySelector('.fcta'),fabsEl=document.getElementById('fabs'),footEl=document.querySelector('.ft'),heroEl=document.querySelector('.hero');
let _overHero=false,_overFoot=false;
function _syncFcta(){if(fcta)fcta.classList.toggle('hide',_overHero||_overFoot);}
if(footEl){const fo=new IntersectionObserver(en=>en.forEach(x=>{
  _overFoot=x.isIntersecting;_syncFcta();
  if(fabsEl)fabsEl.style.transform=x.isIntersecting?'translateY(-70px)':'';
}),{rootMargin:'0px 0px -40px 0px'});fo.observe(footEl);}
if(heroEl){const ho=new IntersectionObserver(en=>en.forEach(x=>{
  _overHero=x.intersectionRatio>0.35;_syncFcta();
}),{threshold:[0,0.35,0.6]});ho.observe(heroEl);}

/* ===== SCROLL ENGINE ===== */
const plxEls=[...document.querySelectorAll('[data-plx]')];
const reduced=matchMedia('(prefers-reduced-motion:reduce)').matches;
function onScroll(){
  const y=scrollY,dh=document.documentElement.scrollHeight-innerHeight;
  progress.style.width=(y/dh*100)+'%';
  hdr.classList.toggle('scr',y>10);
  if(reduced)return;
  plxEls.forEach(el=>{
    const r=el.parentElement.getBoundingClientRect();
    el.style.transform=`translateY(${(r.top+r.height/2-innerHeight/2)*-el.dataset.plx}px)`;
  });
}
addEventListener('scroll',onScroll,{passive:true});addEventListener('resize',onScroll);onScroll();

const io=new IntersectionObserver(en=>en.forEach(x=>{if(x.isIntersecting){x.target.classList.add('in');io.unobserve(x.target)}}),{rootMargin:'-40px'});
document.querySelectorAll('.rv,.rv-l,.rv-r').forEach(el=>io.observe(el));

/* dot-nav active tracking + dark-section styling */
const dots=[...document.querySelectorAll('.dotnav a')];
const secMap=dots.map(d=>document.getElementById(d.dataset.sec)||document.querySelector('#'+d.dataset.sec));
const dio=new IntersectionObserver(en=>{
  en.forEach(x=>{
    if(x.isIntersecting){
      const id=x.target.id;
      dots.forEach(d=>d.classList.toggle('on',d.dataset.sec===id));
      document.getElementById('dotnav').classList.toggle('on-dark',x.target.hasAttribute('data-dark'));
    }
  });
},{rootMargin:'-45% 0px -45% 0px'});
secMap.forEach(s=>s&&dio.observe(s));

/* ===== COUNTERS ===== */
function countUp(el){
  const target=+el.dataset.count,suffix=el.dataset.suffix||'',dur=1800,t0=performance.now();
  function tick(t){const p=Math.min((t-t0)/dur,1);const e=1-Math.pow(1-p,3);
    el.innerHTML=Math.floor(target*e).toLocaleString('en-US')+`<em>${suffix}</em>`;
    if(p<1)requestAnimationFrame(tick)}
  requestAnimationFrame(tick);
}
const cio=new IntersectionObserver(en=>en.forEach(x=>{if(x.isIntersecting){countUp(x.target);cio.unobserve(x.target)}}),{rootMargin:'-30px'});
document.querySelectorAll('[data-count]').forEach(el=>cio.observe(el));

/* ===== TILT ===== */
if(!reduced&&matchMedia('(pointer:fine)').matches){
  document.querySelectorAll('[data-tilt]').forEach(card=>{
    card.addEventListener('mousemove',e=>{
      const r=card.getBoundingClientRect();
      const rx=((e.clientY-r.top)/r.height-.5)*-7,ry=((e.clientX-r.left)/r.width-.5)*7;
      card.style.transform=`perspective(900px) rotateX(${rx}deg) rotateY(${ry}deg) translateY(-6px)`;
    });
    card.addEventListener('mouseleave',()=>{card.style.transform=''});
  });
}

