(function(){
  const map={'privacy':'mPrivacy','terms':'mTerms','disclaimer':'mDisclaimer'};
  function openM(id){const m=document.getElementById(id);if(m){m.classList.add('open');document.body.style.overflow='hidden';}}
  function closeM(m){m.classList.remove('open');if(!document.querySelector('.lmodal.open'))document.body.style.overflow='';}
  document.querySelectorAll('[data-legal]').forEach(a=>a.addEventListener('click',e=>{e.preventDefault();openM(map[a.dataset.legal]);}));
  document.querySelectorAll('.lmodal').forEach(m=>{
    m.querySelectorAll('[data-lclose]').forEach(x=>x.addEventListener('click',()=>closeM(m)));
  });
  document.addEventListener('keydown',e=>{if(e.key==='Escape'){document.querySelectorAll('.lmodal.open').forEach(closeM);}});
})();

